const cfg = $('Confirmation Email Config').item.json;
const trackerItems = $('Query Eligible Trackers').all();
const leadItems = $input.all();
const results = [];

for (let i = 0; i < trackerItems.length; i++) {
  const tracker = trackerItems[i].json;
  const lead = leadItems[i] ? leadItems[i].json : {};

  const tz = tracker.Meeting_Timezone__c || 'America/Los_Angeles';
  let readableDateTime = tracker.Meeting_Start_Date_Time__c || '';
  try {
    const dt = new Date(tracker.Meeting_Start_Date_Time__c);
    readableDateTime = dt.toLocaleString('en-US', {
      timeZone: tz, weekday: 'long', year: 'numeric', month: 'long',
      day: 'numeric', hour: 'numeric', minute: '2-digit', timeZoneName: 'short'
    });
  } catch(e) {}

  const leadName = String(lead.Name || lead.FirstName || tracker.Lead_Email__c || '');
  const leadEmail = String(tracker.Lead_Email__c || lead.Email || '');
  const meetingKey = String(tracker.Meeting_Key__c || '');
  const trackerId = String(tracker.Id || '');
  const outlookEventId = String(tracker.Outlook_Event_ID__c || '');
  const subject = String(tracker.Outlook_Subject__c || '');
  const internalAttendees = String(tracker.Internal_Attendees__c || '');
  const externalAttendees = String(tracker.External_Attendees__c || '');

  const toAddress = cfg.testMode === true
    ? String(cfg.testRecipientOverride || 'user@example.com')
    : String(cfg.colleagueEmail || 'colleague@example.com');

  const emailSubject = 'PREP REMINDER: ' + subject + ' — ' + readableDateTime;

  const bodyHtml =
    '<p>Hi Example Representative,</p>'
    + '<p>This is your internal prep reminder for the upcoming meeting below. Please prepare your discovery notes for Example User before the call.</p>'
    + '<table style="font-family:sans-serif;font-size:14px;border-collapse:collapse;">'
    + '<tr><td style="padding:4px 12px 4px 0;"><b>Lead Name:</b></td><td>' + leadName + '</td></tr>'
    + '<tr><td style="padding:4px 12px 4px 0;"><b>Lead Email:</b></td><td>' + leadEmail + '</td></tr>'
    + '<tr><td style="padding:4px 12px 4px 0;"><b>Meeting Subject:</b></td><td>' + subject + '</td></tr>'
    + '<tr><td style="padding:4px 12px 4px 0;"><b>Meeting Time:</b></td><td><strong>' + readableDateTime + '</strong></td></tr>'
    + '<tr><td style="padding:4px 12px 4px 0;"><b>Meeting Timezone:</b></td><td>' + tz + '</td></tr>'
    + '<tr><td style="padding:4px 12px 4px 0;"><b>Internal Attendees:</b></td><td>' + internalAttendees + '</td></tr>'
    + '<tr><td style="padding:4px 12px 4px 0;"><b>External Attendees:</b></td><td>' + externalAttendees + '</td></tr>'
    + '</table>'
    + '<p>Please prepare your discovery meeting notes/template for Example User before this call.</p>'
    + '<p><em>Internal reminder only. Do not reply to the lead from this email.</em></p>'
    + '<p><em>This is an automated internal reminder from n8n.</em></p>';

  results.push({ json: {
    trackerId, meetingKey,
    leadId: String(tracker.Related_Lead__c || ''),
    leadName, leadEmail, toAddress, emailSubject, bodyHtml, readableDateTime,
    testMode: cfg.testMode === true,
    draftMode: cfg.draftMode === true
  }});
}
return results.length > 0 ? results : [{ json: { noEligible: true } }];
